import sys

def main():
    data = sys.stdin.read().split()
    t = int(data[0])
    pairs = {")": "(", "]": "[", "}": "{"}
    out = []
    for i in range(1, t + 1):
        s = data[i]
        stack = []
        ok = True
        for ch in s:
            if ch in "([{":
                stack.append(ch)
            elif not stack or stack.pop() != pairs[ch]:
                ok = False
                break
        out.append("YES" if ok and not stack else "NO")
    print("\n".join(out))

main()
